const t={name:"Schalottenlök",icon:"schalottenlok",family:"Lökväxter",familyLatin:"Amaryllidaceae",difficulty:"Enkel",difficultyWhy:"Sättlök i jorden, vänta, skörda en hel klunga lökar. Schalottenlöken gör det mesta jobbet själv - hon delar sig och multiplicerar utan att du lyfter ett finger.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:null},days:"90-120",spacing:"15-20 cm",rowSpacing:"25-30 cm",depth:"2-3 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Schalottenlöken är solälskare precis som sin kusin vanlig lök. Minst 6 timmar direkt solljus per dag. I halvskugga får du bladmassa men klena, outvecklade klungor."},temperature:{min:5,max:30,ideal:"15-22°C",detail:"Tålig liten dam som klarar lätt frost som etablerad planta. Trivs bäst i svalare väder under tillväxten och lite varmare när lökarna mognar och delar sig."},wind:{level:"Tålig",detail:"Med sin låga profil bryr sig schalottenlöken inte nämnvärt om vind. Inga särskilda åtgärder behövs."}},watering:{need:"Låg-Medel",icon:"water",summary:"Schalottenlöken vill ha jämn, lätt fukt under tillväxten men HATAR blöta fötter. Ännu känsligare för övervattning än vanlig lök - hon ruttnar lätt om det står vatten. När blasten börjar gulna och lägga sig - sluta vattna helt.",phases:[{phase:"Etablering (0-3 veckor)",need:"Medel",tip:"Håll jorden lätt fuktig efter sättning så rötterna kan etablera sig. Vattna 1-2 gånger i veckan om det inte regnar. Undvik att blöta ner själva sättlöken."},{phase:"Tillväxt (3-10 veckor)",need:"Medel",tip:"Jämn fukt utan att överdriva. Schalottenlöken bygger nu sin klunga och behöver vatten - men aldrig stående vatten. Mulcha gärna för att hålla fukt och ogräs borta."},{phase:"Delning och lökbildning (10-14 veckor)",need:"Låg",tip:"Minska vattningen gradvis. Klungan delar sig och varje lök bygger upp sina lager. För mycket vatten ger vattniga lökar som lagras dåligt."},{phase:"Mognad (sista 2-3 veckorna)",need:"Ingen",tip:"SLUTA vattna helt när blasten gulnar och lägger sig. Lökarna ska torka och bilda ordentligt skal. Vatten nu förstör den fantastiska lagringsförmågan."}],mistakes:["Vattna när blasten redan lagt sig - lökarna ruttnar istället för att mogna","Övervattning generellt - schalottenlök är ännu känsligare än vanlig lök","Stående vatten runt klungan - dränering är helt avgörande"],tip:"Mulcha med halm eller gräsklipp mellan raderna. Det håller fukten jämn, ogräset borta och jorden sval - precis som schalottenlöken vill ha det."},soil:"Väldränderad, lätt, mullrik jord. Schalottenlöken vill ha det luftigt - tung lerjord är hennes fiende nummer ett. Blanda i sand och kompost om jorden är tung.",soilTips:["Luckra ordentligt till 20 cm djup - klungan behöver plats att breda ut sig","Blanda in sand och väl brunnen kompost i tung jord","Upphöjda bäddar är perfekta - bra dränering och varm jord","Strö lite trädgårdskalk om pH är under 6","Undvik FÖR rik jord - det ger mycket blast men små lökar"],timeline:{1:[{phase:"Sätt sättlök",months:"Apr",icon:"seedling"},{phase:"Rensa ogräs",months:"Maj-Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul",icon:"water"},{phase:"Skörd och torkning",months:"Aug",icon:"harvest"}],4:[{phase:"Sätt sättlök",months:"Apr-Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun",icon:"leaf"},{phase:"Minska vattning",months:"Jul-Aug",icon:"water"},{phase:"Skörd och torkning",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Sätt sättlök",months:"Maj",icon:"seedling"},{phase:"Rensa ogräs",months:"Jun-Jul",icon:"leaf"},{phase:"Minska vattning",months:"Aug",icon:"water"},{phase:"Skörd och torkning",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:25,P:15,K:10,label:"Sättning"},{month:"Maj",N:55,P:25,K:20,label:"Tillväxt"},{month:"Jun",N:65,P:35,K:30,label:"Bladtillväxt"},{month:"Jul",N:25,P:45,K:60,label:"Delning och lökbildning"},{month:"Aug",N:10,P:35,K:75,label:"Mognad"},{month:"Sep",N:5,P:20,K:45,label:"Skörd"}],nutritionTips:[{timing:"Vid sättning",tip:"Grundgödsla med brunnen kompost. Lite benmjöl i planteringshålet ger bra fosfortillskott för rotutvecklingen. Gå lätt på kvävet - schalottenlöken behöver mindre än vanlig lök."},{timing:"Tidig tillväxt",tip:"Lätt giva flytande gödsel varannan vecka. Lagom med kväve - för mycket ger yvig blast och dålig delning."},{timing:"Delning och lökbildning",tip:"Sluta med kväve helt. Ge kaliumrik gödsel (vedaska) - det hjälper varje lök i klungan att bilda fina, fasta lager."},{timing:"Mognad",tip:"Ingen gödsling. Låt lökkklungan mogna ifred."}],companions:{good:[{id:"morot",name:"Morot",icon:"vegetable",why:"Klassiskt radarpar - schalottenlökens doft skrämmer bort morotsflugan och moroten håller lökflugan borta"},{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Lökdoften skyddar jordgubbarna mot gråmögel - fungerar precis som med vanlig lök"},{id:"sallat",name:"Sallat",icon:"vegetable",why:"Smart markutnyttjande - sallaten skördas innan schalottenlöken behöver all plats för sin klunga"}],bad:[{id:"artor",name:"Ärtor",icon:"vegetable",why:"Lökväxter hämmar ärtornas tillväxt - de trivs inte alls ihop"},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Samma problem som ärtor - baljväxter och lökväxter funkar inte ihop"}]},rotation:{avoid:[{id:"lok",name:"Lök"},{id:"vitlok",name:"Vitlök"},{id:"purjolok",name:"Purjolök"},{id:"graslok",name:"Gräslök"}],avoidWhy:"Alla tillhör lökväxter (Amaryllidaceae) - delar sjukdomar som lökröta och lökfluga. Vänta minst 4 år.",goodBefore:[{name:"Kål"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Näringshungriga grödor drar nytta av den välgödslade jord schalottenlöken lämnar efter sig.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter fixerar kväve i jorden och bygger upp näringen inför nästa säsong."},varieties:[{name:"Jermor",zones:[1,2,3,4,5],note:"Halvlång bananschalottenlök och en riktig lagringskunglighet. Pålitlig sort som ger jämna, fina klungor. Larsviken."},{name:"Zebrune",zones:[1,2,3,4,5],note:"Avlång och elegant med mild, fin smak och silkig textur. En favorit bland kockar. Fröodlad. Impecta."},{name:"Longor",zones:[1,2,3,4,5],note:"Lång, rödskälig bananschalottenlök med bra skörd och fin smak. Lagrar bra. Nelson Garden (sättlök)."},{name:"Golden Gourmet",zones:[1,2,3,4,5,6],note:"Rund, gul och mild. Tidig sort som passar bra även i kallare zoner. Wexthuset, Plantagen m.fl."}],problems:[{name:"Lökfluga",symptom:"Gula, slappa blad. Larver vid lökarnas bas som äter sig in.",fix:"Täck med fiberduk i maj-juni. Samodla med morot. Strö kalkstensmjöl vid basen av klungan."},{name:"Lökröta (Botrytis)",symptom:"Mjukt, grått mögel vid halsen. Lökarna ruttnar vid lagring.",fix:"Torka klungorna ordentligt efter skörd. Skörda i torrt väder. God ventilation vid lagring."},{name:"Falskt mjöldagg",symptom:"Blågrå beläggning på bladen. Blasten vissnar tidigt.",fix:"Växtföljd! Undvik övervattning och plantera luftigt. Plocka bort angripna plantor direkt."},{name:"För tidig skottbildning",symptom:"Löken skjuter blomstjälk redan första året istället för att bilda klunga.",fix:"Förvara sättlöken svalt (inte under 5°C) innan sättning. Välj värmebehandlad sättlök. Sätt inte för tidigt i kall jord."}],goodToKnow:[{icon:"seedling",title:"En blir MÅNGA - magisk multiplikation!",text:"Det här är schalottenlökens superkraft - en enda sättlök delar sig och blir en klunga på 5-12 lökar. Fantastisk avkastning på din investering! Spara de finaste lökarna som sättlök till nästa år.",severity:"tip"},{icon:"leaf",title:"Gourmetsmak i en enkel lök",text:"Schalottenlöken har en mildare, sötare och mer komplex smak än vanlig lök. Det är inte utan anledning att franska kockar älskar den. Perfekt rå i vinaigretter eller karamelliserad.",severity:"tip"},{icon:"storage",title:"Lagringsdrottningen",text:"Ordentligt torkade schalottenlökar lagrar ofta 6-8 månader - bättre än de flesta vanliga lökar! Hemligheten är den extra torktiden och bra luftcirkulation.",severity:"tip"},{icon:"sun",title:"Daglängd styr lökbildningen",text:"Precis som vanlig lök styrs schalottenlökens lökbildning av daglängden. Sätt tidigt på säsongen så hon hinner bygga ordentlig blast innan de långa dagarna triggar lökbildningen.",severity:"tip"},{icon:"seedling",title:"Sättlök framför frösådd - alltid",text:"Schalottenlök odlas traditionellt från sättlök, och det finns goda skäl. Frösådd tar mycket längre tid och ger ofta sämre resultat. Sättlök ger pålitliga klungor redan första säsongen.",severity:"tip"},{icon:"warning",title:"Tung lera? Tänk om!",text:"Schalottenlöken avskyr tung, vattensjuk lera mer än sin kusin vanlig lök. Klungan behöver kunna breda ut sig i luftig jord. En upphöjd bädd med sandblandad kompost gör underverk.",severity:"warning"}],sowing:{method:"both",label:"Sättlök eller frösådd",description:"Sättlök rekommenderas starkt - det är traditionellt och ger bäst resultat. Varje sättlök delar sig till en klunga på 5-12 lökar. Frösådd är möjligt men tar längre tid och ger ofta mindre klungor.",steps:["Sättlök: Tryck ner sättlöken i jorden med spetsen uppåt, 2-3 cm djupt","Spetsen ska precis sticka upp ovanför jordytan","Avstånd 15-20 cm i raden (klungan behöver plats att breda ut sig!), 25-30 cm mellan raderna","Vattna lätt efter sättning","Frösådd: Förkultivera inomhus i februari-mars (8-10 veckor före utplantering)","Så tunt i djupa krukor - lökplantor vill inte bli omplacerade","Plantera ut efter avhärdning när frostrisken är över"],tips:["Välj värmebehandlad sättlök - det minskar risken för tidig skottbildning","Sätt inte sättlöken för djupt - klungan behöver kunna breda ut sig nära ytan","Lite benmjöl i planteringshålet ger stark rotutveckling","Spara de finaste lökarna från årets skörd som sättlök till nästa år - gratis multiplikation!"],indoorWeeks:"8-10 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Schalottenlöken är tvåårig - första året bildar hon klunga, andra året blommar hon och sätter frö. Du behöver överväntra utvalda lökar och plantera ut dem igen. De flesta odlare sparar istället sättlök från klungan - mycket enklare!",steps:["Välj de finaste, friskaste lökarna från de bästa klungorna vid skörd","Lagra dem svalt (4-8°C) men frostfritt över vintern","Plantera ut hela löken tidigt på våren med halsen i marknivå","Löken skjuter en hög blomstjälk med rund blomkula","Insekter pollinerar blommorna under sommaren","Låt frökapsarna mogna tills de börjar öppna sig och visa svarta frön","Klipp av hela blomhuvudet och torka inomhus i en papperspåse","Skaka ut fröna när de är helt torra"],isolation:"Korsar med andra sorter av schalottenlök och potentiellt med vanlig lök (båda Allium cepa). Isolera med minst 1 km eller odla bara en sort för frö.",storageYears:"1-3 år",tip:"Enklare alternativ: spara bara de bästa lökarna ur klungan som sättlök till nästa år! Det är så schalottenlök traditionellt förökas - och det bevarar sortegenskaperna perfekt."},storage:{shelfLife:"4-8 månader",methods:[{method:"Hängande i nätpåse",icon:"storage",duration:"6-8 månader",description:"Häng klungorna i nätpåsar eller fläta ihop dem i strängar på en sval, torr plats. Schalottenlökens fantastiska lagringsförmåga kommer verkligen till sin rätt här. Bättre hållbarhet än vanlig lök!",best:!0},{method:"Sval förvaring (källare)",icon:"storage",duration:"4-6 månader",description:"Lägg lökarna i lådor med god ventilation, gärna i ett enda lager. Temperatur 1-5°C och låg luftfuktighet. Kolla regelbundet att ingen börjat mögla.",best:!1},{method:"Frysa (hackad)",icon:"snowflake",duration:"6-8 månader",description:"Hacka lökarna och frys in i portionspåsar. Perfekt för matlagning - den milda smaken bevaras bra. Behöver inte tinas innan den hamnar i pannan.",best:!1},{method:"Torka",icon:"sun",duration:"12+ månader",description:"Skiva tunt och torka i ugn på 55°C eller i torkautomat. Ger ett fantastiskt fint lökpulver med mer komplex smak än vanligt lökpulver.",best:!1}],tips:["Torka klungorna ordentligt (2-3 veckor) efter skörd - det är hemligheten bakom den långa hållbarheten","Schalottenlök lagrar ofta BÄTTRE än vanlig lök - räkna med 6-8 månader i bra förhållanden","Lagra aldrig tillsammans med potatis - de avger gaser som påskyndar förruttnelse","Spara de finaste lökarna som sättlök till nästa säsong istället för att äta upp alla!"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}};export{t as schalottenlok};
